using namespace std;

int main() {
    int t;
    cin >> t;

    while (t--) {
        string s;
        cin >> s;
        vector<int> arr(26, 0);  // Array to hold frequency of each character
        int maxi = 0;

        for (char ch : s) {
            arr[ch - 'a']++;
            maxi = max(maxi, arr[ch - 'a']);
        }

        cout << s.length() - maxi << endl;
    }

    return 0;
}

