#include <stdio.h>
#include <string.h>

int main() {
    int t;
    scanf("%d", &t);

    while (t--) {
        char s[1001];
        scanf("%s", s);
        int arr[26] = {0};  // Array to hold frequency of each character
        int maxi = 0;
        int n = strlen(s);

        for (int i = 0; i < n; i++) {
            int idx = s[i] - 'a';
            arr[idx]++;
            if (arr[idx] > maxi) {
                maxi = arr[idx];
            }
        }

        printf("%d\n", n - maxi);
    }

    return 0;
}

